from flask import Flask, request, redirect, session, url_for, jsonify
import requests
import json
import base64
import hashlib
import secrets
import urllib.parse
from cryptography.hazmat.primitives import hashes
from cryptography.hazmat.primitives.asymmetric import rsa, padding
from cryptography.hazmat.primitives import serialization
import time

app = Flask(__name__)
app.secret_key = secrets.token_hex(32)

# Configuration
OIDC_CONFIG = {
    'issuer': 'https://your-oidc-provider.com',
    'client_id': 'your_client_id',
    'client_secret': 'your_client_secret',
    'redirect_uri': 'http://localhost:5000/callback',
    'scope': 'openid profile email'
}

# Cache for storing nonces and PKCE codes
nonce_cache = {}
pkce_cache = {}

def get_oidc_config():
    return OIDC_CONFIG

def generate_nonce():
    return secrets.token_urlsafe(32)

def generate_pkce_code():
    code_verifier = secrets.token_urlsafe(32)
    code_challenge = base64.urlsafe_b64encode(
        hashlib.sha256(code_verifier.encode()).digest()
    ).decode().rstrip('=')
    return code_verifier, code_challenge

def decode_jwt(token):
    try:
        header, payload, signature = token.split('.')
        # Add padding if needed
        payload += '=' * (4 - len(payload) % 4)
        decoded_payload = base64.urlsafe_b64decode(payload)
        return json.loads(decoded_payload)
    except Exception:
        return None

@app.route('/')
def index():
    return '<a href="/login">Login with OpenID Connect</a>'

@app.route('/login')
def login():
    config = get_oidc_config()
    nonce = generate_nonce()
    code_verifier, code_challenge = generate_pkce_code()
    
    # Store nonce and PKCE in cache
    nonce_cache[nonce] = time.time()
    pkce_cache[code_verifier] = code_challenge
    
    # Build authorization URL
    auth_url = f"{config['issuer']}/authorize"
    params = {
        'response_type': 'code',
        'client_id': config['client_id'],
        'redirect_uri': config['redirect_uri'],
        'scope': config['scope'],
        'nonce': nonce,
        'code_challenge': code_challenge,
        'code_challenge_method': 'S256'
    }
    
    query_string = urllib.parse.urlencode(params)
    redirect_url = f"{auth_url}?{query_string}"
    
    # Store state in session
    session['state'] = secrets.token_urlsafe(32)
    session['nonce'] = nonce
    session['code_verifier'] = code_verifier
    
    return redirect(redirect_url)

@app.route('/callback')
def callback():
    config = get_oidc_config()
    
    # Validate state parameter
    if 'state' not in request.args or request.args['state'] != session.get('state'):
        return "Invalid state parameter", 400
    
    # Get authorization code
    if 'code' not in request.args:
        return "Authorization code not found", 400
    
    code = request.args['code']
    nonce = session.get('nonce')
    code_verifier = session.get('code_verifier')
    
    # Validate nonce
    if not nonce or nonce not in nonce_cache:
        return "Invalid nonce", 400
    
    # Remove nonce from cache
    del nonce_cache[nonce]
    
    # Exchange code for tokens
    token_url = f"{config['issuer']}/token"
    headers = {
        'Content-Type': 'application/x-www-form-urlencoded',
        'Authorization': f"Basic {base64.b64encode(f'{config['client_id']}:{config['client_secret']}'.encode()).decode()}"
    }
    
    data = {
        'grant_type': 'authorization_code',
        'code': code,
        'redirect_uri': config['redirect_uri'],
        'code_verifier': code_verifier
    }
    
    try:
        response = requests.post(token_url, headers=headers, data=data)
        response.raise_for_status()
        token_data = response.json()
        
        # Decode ID token
        id_token = token_data.get('id_token')
        if not id_token:
            return "ID token not found", 400
        
        payload = decode_jwt(id_token)
        if not payload:
            return "Failed to decode ID token", 400
        
        # Validate nonce
        if payload.get('nonce') != nonce:
            return "Invalid nonce in ID token", 400
        
        # Validate issuer
        if payload.get('iss') != config['issuer']:
            return "Invalid issuer", 400
        
        # Store user info in session
        session['user'] = {
            'sub': payload.get('sub'),
            'name': payload.get('name'),
            'email': payload.get('email'),
            'preferred_username': payload.get('preferred_username')
        }
        
        return redirect(url_for('dashboard'))
        
    except requests.RequestException as e:
        return f"Token exchange failed: {str(e)}", 500
    except Exception as e:
        return f"Error processing callback: {str(e)}", 500

@app.route('/dashboard')
def dashboard():
    if 'user' not in session:
        return redirect(url_for('login'))
    
    user = session['user']
    return f"""
    <h1>Dashboard</h1>
    <p>Welcome, {user.get('name', 'User')}!</p>
    <p>Email: {user.get('email', 'N/A')}</p>
    <p><a href="/logout">Logout</a></p>
    """

